			["url"] = "https://wago.io/TazaveshConsole/7",
			["actions"] = {
				["start"] = {
					["custom"] = "aura_env.topLeft = false\naura_env.topRight = false\naura_env.bottomLeft = false\naura_env.bottomRight = false\nWeakAuras.ScanEvents(\"HYLB_RESET\", true)",
					["do_custom"] = true,
				},
				["finish"] = {
				},
				["init"] = {
					["custom"] = "aura_env.region.clickMe = aura_env.region.clickMe or CreateFrame(\"Button\", nil, aura_env.region)\naura_env.region.clickMe:SetAllPoints()\naura_env.region.clickMe:SetScript(\"OnClick\", function()\n        WeakAuras.ScanEvents(\"HYLB_SEND\", true)\nend)\naura_env.region.clickMe:SetHighlightTexture(\"Interface\\\\QuestFrame\\\\UI-QuestLogTitleHighlight\", \"ADD\")\n\naura_env.topLeft = false\naura_env.topRight = false\naura_env.bottomLeft = false\naura_env.bottomRight = false\n\naura_env.send = function(text)\n    local chatType = \"PARTY\"\n    if IsInGroup(LE_PARTY_CATEGORY_INSTANCE) then\n        chatType = \"INSTANCE_CHAT\"\n    end\n    if not IsInGroup() then\n        print(text)\n    else\n        SendChatMessage(text, chatType)\n    end\nend\n\n\n",
					["do_custom"] = true,
				},
			},
			["triggers"] = {
				{
					["trigger"] = {
						["type"] = "custom",
						["subeventSuffix"] = "_CAST_START",
						["event"] = "Health",
						["unit"] = "player",
						["debuffType"] = "HELPFUL",
						["custom"] = "function(event, arg1, arg2, arg3)\n    if event == \"HYLB_RESET\" and arg1 then\n        aura_env.topLeft = false\n        aura_env.topRight = false\n        aura_env.bottomLeft = false\n        aura_env.bottomRight = false\n    elseif event == \"HYLB_TOPLEFT\" and arg2 then\n        aura_env.topLeft = arg2\n    elseif event == \"HYLB_TOPRIGHT\" and arg2 then\n        aura_env.topRight = arg2\n    elseif event == \"HYLB_BOTTOMLEFT\" and arg2 then\n        aura_env.bottomLeft = arg2\n    elseif event == \"HYLB_BOTTOMRIGHT\" and arg2 then\n        aura_env.bottomRight = arg2\n    elseif event == \"HYLB_SEND\" and arg1 \n    and aura_env.topLeft and aura_env.topRight\n    and aura_env.bottomLeft and aura_env.bottomRight\n    then\n        local message = format(\"%s*%s*%s*%s\", aura_env.topLeft, aura_env.topRight, aura_env.bottomLeft, aura_env.bottomRight)\n        C_ChatInfo.SendAddonMessage(\"HYLB_PERSONAL\", message, IsInGroup(LE_PARTY_CATEGORY_INSTANCE) and \"INSTANCE_CHAT\" or \"PARTY\")\n        \n        local text = format(\"%s   %s\", aura_env.topLeft, aura_env.topRight)\n        aura_env.send(text)\n        \n        text = format(\"%s   %s\", aura_env.bottomLeft, aura_env.bottomRight)\n        aura_env.send(text)\n    end\nend",
						["spellIds"] = {
						},
						["custom_type"] = "event",
