						["check"] = "event",
						["unit"] = "player",
						["custom"] = "function(states, event, ...)\n    if event == \"COMBAT_LOG_EVENT_UNFILTERED\" and ... then\n        local _, message, _, srcGUID, srcName, _, _, destGUID, destName, _, _, spellid = ...\n        if message == \"SPELL_AURA_APPLIED\"\n        and destGUID == WeakAuras.myGUID\n        and spellid == 346427\n        then\n            states[\"\"] = {\n                name = \"Titanic Insight\",\n                icon = 135918,\n                duration = 15,\n                expirationTime = GetTime() + 15,\n                progressType = \"timed\",\n                autoHide = true,\n                changed = true,\n                show = true,\n            }\n        elseif message == \"SPELL_AURA_REMOVED\"\n        and destGUID == WeakAuras.myGUID\n        and spellid == 346427\n        and states[\"\"]\n        then\n            states[\"\"].show = false\n            states[\"\"].changed = true\n            return true\n        end\n    end\nend",
