						["type"] = "custom",
						["duration"] = "5",
						["unevent"] = "timed",
						["spellName"] = 0,
						["spellIds"] = {
						},
						["event"] = "Combat Log",
						["custom"] = "function()\n    local unit = \"mouseover\"\n    \n    -- Don't continue if the unit shouldn't be marked\n    if aura_env.UnitIsInCombatWithParty(unit) or GetRaidTargetIndex(unit) or not UnitExists(unit) then return end\n    local npcId, _ = select(6, strsplit(\"-\", UnitGUID(unit)))\n    if not aura_env.enemies or not aura_env.enemies[npcId] then return end\n    \n    aura_env.SetupTables()\n    aura_env.GetUsedMarkers()\n    \n    -- Select enemies for marking\n    if aura_env.CheckMouseoverModifier() then\n        aura_env.SelectEnemyToMark(unit)\n    end\n    \n    -- Mark enemies\n    aura_env.MarkEnemies(aura_env.chosenMarkers1, aura_env.enemiesToMark1)\n    aura_env.MarkEnemies(aura_env.chosenMarkers2, aura_env.enemiesToMark2)\n    aura_env.MarkEnemies(aura_env.chosenMarkers3, aura_env.enemiesToMark3)\nend",
