				["init"] = {
					["custom"] = "aura_env.lastRangeCheck = 0;\naura_env.rangeCheckUpdateRate = 0.25;\naura_env.rangeCheckRange = 2.6;\n\naura_env.doRangeCheck = function()\n    \n    aura_env.peopleTooClose = {};\n    local min,name;\n    \n    --for _,player in pairs(aura_env.debugTable) do\n    for player in WA_IterateGroupMembers() do\n        min = WeakAuras.GetRange(player);\n        name = UnitName(player);\n        if(name ~= WeakAuras.me and aura_env.rangeCheckRange > min)then\n            table.insert(aura_env.peopleTooClose,name);\n        end\n    end\n    \n    if(#aura_env.peopleTooClose == 0)then\n        aura_env.region:Color(0,1,0,1);\n    else\n        aura_env.region:Color(1,0,0,1);\n    end\n    \nend",
