			["displayText"] = "%c\n",
			["customText"] = "function()\n    aura_env.UpdateRemainingPercentage()\n    return aura_env.DisplayText\nend\n\n\n",
			["yOffset"] = 0,
			["anchorPoint"] = "CENTER",
			["displayText_format_p_time_format"] = 0,
