				["init"] = {
					["custom"] = "local SECTION = 1\nlocal DUNGEONS = {}\nlocal DUNGEONID = 0\nlocal DUNGEONDEFAULT = {\n    --           {bossID, neededPercent, shouldInfom, haveInformed}\n    [2284] = {{1,     0, false, false}, {2, 68.96, true , false}, {3,     0, false, false}, {4, 100, true , false}}, -- [SD]   Sanguine Depths   \n    [2285] = {{1,     0, false, false}, {2,     0, false, false}, {3, 87.37, true , false}, {4, 100, true , false}}, -- [SoA]  Spires of Ascension\n    [2286] = {{1,     0, false, false}, {2, 68.20, true , false}, {3,     0, false, false}, {4, 100, true , false}}, -- [NW]   The Necrotic Wake\n    [2287] = {{1,     0, false, false}, {2, 79.49, true , false}, {3, 92.67, false, false}, {4, 100, true , false}}, -- [HoA]  Halls of Atonement\n    [2289] = {{1,     0, false, false}, {2,     0, false, false}, {3, 84.50, true , false}, {4, 100, true , false}}, -- [PF]   Plaguefall\n    [2290] = {{1,     0, false, false}, {2,     0, false, false}, {3,   100, true , false}},                         -- [MoTS] Mists of Tirna Scithe\n    [2291] = {{1,     0, false, false}, {2,     0, false, false}, {3,     0, false, false}, {4, 100, true , false}}, -- [DoS]   De Other Side\n    [2293] = {{1,     0, false, false}, {2,     0, false, false}, {3,     0, false, false}, {4,   0, false, false}, {5, 100, true , false}}, -- [ToP] Theater of Pain\n    [2441] = {{1,     0, false, false}, {2,     0, false, false}, {3,     0, false, false}, {4,   0, false, false}, {5, 100, true , false}}, -- [STRT] Tazavesh: Streets of Wonder\n    [24410] = {{1, 49.42, true , false}, {2,     0, false, false}, {3,   100, true, false}}, -- [GMBT] Tazavesh: So'leah's Gambit \n}\n\n\nlocal HoANumOfLoyalStoneborn = { -- Halls of Atonement Number of Loyal Stoneborn\n    [0] = 79.49, -- skip gargoyle in front for the 3 boss\n    [1] = 78.02, -- Include one gargoyle in front for the 3 boss\n    [2] = 76.56, -- Include both gargoyle in front for the 3 boss\n}\n\n\nlocal CHANNELCONVERTER = {\n    [1] = \"party\",\n    [2] = \"say\",\n    [3] = \"yell\",\n}\n\naura_env.ChangeDungeonIdForTazaveshGambit = function(dungeonId)\n    if dungeonId == 2441 and C_Scenario.GetCriteriaInfo(5) == nil then\n        return 24410\n    end\n    return dungeonId\nend\n\naura_env.SetDungeonValues = function(dungeonId, bossId, neededPercent, shouldInfom)\n    if DUNGEONS == nil then return end\n    for var = 1, 5 do\n        if  DUNGEONS[dungeonId][var] ~= nil and DUNGEONS[dungeonId][var][1] == bossId then\n            DUNGEONS[dungeonId][var] = {bossId, neededPercent, shouldInfom, DUNGEONS[dungeonId][var][4]}\n            return\n        end\n    end\nend\n\n\naura_env.GetDungeonPercent = function(dungeonId, bossId)\n    if DUNGEONS == nil then return end\n    for var = 1, 5 do\n        if  DUNGEONS[dungeonId][var] ~= nil and DUNGEONS[dungeonId][var][1] == bossId then\n            return DUNGEONS[dungeonId][var][2]\n        end\n    end\nend\n\n\naura_env.AdvancedOptions = function()\n    if aura_env.config.AO.IsAdvancedOptionSelected == false then \n        DUNGEONS = DUNGEONDEFAULT\n        aura_env.SortDungeonData()\n        return \n    end\n    \n    --[SD]      Sanguine Depths \n    aura_env.SetDungeonValues(2284, 1, aura_env.config.AO.SD.BossOne,       aura_env.config.AO.SD.BossOneInform)\n    aura_env.SetDungeonValues(2284, 2, aura_env.config.AO.SD.BossTwo,       aura_env.config.AO.SD.BossTwoInform)\n    aura_env.SetDungeonValues(2284, 3, aura_env.config.AO.SD.BossThree,     aura_env.config.AO.SD.BossThreeInform)\n    aura_env.SetDungeonValues(2284, 4, aura_env.config.AO.SD.BossFour,      aura_env.config.AO.SD.BossFourInform)\n    \n    --[SoA]     Spires of Ascension\n    aura_env.SetDungeonValues(2285, 1, aura_env.config.AO.SoA.BossOne,      aura_env.config.AO.SoA.BossOneInform)\n    aura_env.SetDungeonValues(2285, 2, aura_env.config.AO.SoA.BossTwo,      aura_env.config.AO.SoA.BossTwoInform)\n    aura_env.SetDungeonValues(2285, 3, aura_env.config.AO.SoA.BossThree,    aura_env.config.AO.SoA.BossThreeInform)\n    aura_env.SetDungeonValues(2285, 4, aura_env.config.AO.SoA.BossFour,     aura_env.config.AO.SoA.BossFourInform)\n    \n    --[NW]      The Necrotic Wake\n    aura_env.SetDungeonValues(2286, 1, aura_env.config.AO.NW.BossOne,       aura_env.config.AO.NW.BossOneInform)\n    aura_env.SetDungeonValues(2286, 2, aura_env.config.AO.NW.BossTwo,       aura_env.config.AO.NW.BossTwoInform)\n    aura_env.SetDungeonValues(2286, 3, aura_env.config.AO.NW.BossThree,     aura_env.config.AO.NW.BossThreeInform)\n    aura_env.SetDungeonValues(2286, 4, aura_env.config.AO.NW.BossFour,      aura_env.config.AO.NW.BossFourInform)\n    \n    --[HoA]     Halls of Atonement\n    aura_env.SetDungeonValues(2287, 1, aura_env.config.AO.HoA.BossOne,      aura_env.config.AO.HoA.BossOneInform)\n    aura_env.SetDungeonValues(2287, 2, aura_env.config.AO.HoA.BossTwo,      aura_env.config.AO.HoA.BossTwoInform)\n    aura_env.SetDungeonValues(2287, 3, aura_env.config.AO.HoA.BossThree,    aura_env.config.AO.HoA.BossThreeInform)\n    aura_env.SetDungeonValues(2287, 4, aura_env.config.AO.HoA.BossFour,     aura_env.config.AO.HoA.BossFourInform)\n    \n    --[PF]      Plaguefall\n    aura_env.SetDungeonValues(2289, 1, aura_env.config.AO.PF.BossOne,       aura_env.config.AO.PF.BossOneInform)\n    aura_env.SetDungeonValues(2289, 2, aura_env.config.AO.PF.BossTwo,       aura_env.config.AO.PF.BossTwoInform)\n    aura_env.SetDungeonValues(2289, 3, aura_env.config.AO.PF.BossThree,     aura_env.config.AO.PF.BossThreeInform)\n    aura_env.SetDungeonValues(2289, 4, aura_env.config.AO.PF.BossFour,      aura_env.config.AO.PF.BossFourInform)\n    \n    --[MoTS]    Mists of Tirna Scithe\n    aura_env.SetDungeonValues(2290, 1, aura_env.config.AO.MoTS.BossOne,     aura_env.config.AO.MoTS.BossOneInform)\n    aura_env.SetDungeonValues(2290, 2, aura_env.config.AO.MoTS.BossTwo,     aura_env.config.AO.MoTS.BossTwoInform)\n    aura_env.SetDungeonValues(2290, 3, aura_env.config.AO.MoTS.BossThree,   aura_env.config.AO.MoTS.BossThreeInform)\n    \n    --[DoS]     De Other Side\n    aura_env.SetDungeonValues(2291, 1, aura_env.config.AO.DoS.BossOne,      aura_env.config.AO.DoS.BossOneInform)\n    aura_env.SetDungeonValues(2291, 2, aura_env.config.AO.DoS.BossTwo,      aura_env.config.AO.DoS.BossTwoInform)\n    aura_env.SetDungeonValues(2291, 3, aura_env.config.AO.DoS.BossThree,    aura_env.config.AO.DoS.BossThreeInform)\n    aura_env.SetDungeonValues(2291, 4, aura_env.config.AO.DoS.BossFour,     aura_env.config.AO.DoS.BossFourInform)\n    \n    --[ToP]     Theater of Pain \n    aura_env.SetDungeonValues(2293, 1, aura_env.config.AO.ToP.BossOne,      aura_env.config.AO.ToP.BossOneInform)\n    aura_env.SetDungeonValues(2293, 2, aura_env.config.AO.ToP.BossTwo,      aura_env.config.AO.ToP.BossTwoInform)\n    aura_env.SetDungeonValues(2293, 3, aura_env.config.AO.ToP.BossThree,    aura_env.config.AO.ToP.BossThreeInform)\n    aura_env.SetDungeonValues(2293, 4, aura_env.config.AO.ToP.BossFour,     aura_env.config.AO.ToP.BossFourInform)\n    aura_env.SetDungeonValues(2293, 5, aura_env.config.AO.ToP.BossFive,     aura_env.config.AO.ToP.BossFiveInform)\n    \n    --[STRT]    Tazavesh: Streets of Wonder\n    aura_env.SetDungeonValues(2441, 1, aura_env.config.AO.STRT.BossOne,      aura_env.config.AO.STRT.BossOneInform)\n    aura_env.SetDungeonValues(2441, 2, aura_env.config.AO.STRT.BossTwo,      aura_env.config.AO.STRT.BossTwoInform)\n    aura_env.SetDungeonValues(2441, 3, aura_env.config.AO.STRT.BossThree,    aura_env.config.AO.STRT.BossThreeInform)\n    aura_env.SetDungeonValues(2441, 4, aura_env.config.AO.STRT.BossFour,     aura_env.config.AO.STRT.BossFourInform)\n    aura_env.SetDungeonValues(2441, 5, aura_env.config.AO.STRT.BossFive,     aura_env.config.AO.STRT.BossFiveInform)\n    \n    --[GMBT]    Tazavesh: So'leah's Gambit\n    aura_env.SetDungeonValues(24410, 1, aura_env.config.AO.GMBT.BossOne,      aura_env.config.AO.GMBT.BossOneInform)\n    aura_env.SetDungeonValues(24410, 2, aura_env.config.AO.GMBT.BossTwo,      aura_env.config.AO.GMBT.BossTwoInform)\n    aura_env.SetDungeonValues(24410, 3, aura_env.config.AO.GMBT.BossThree,    aura_env.config.AO.GMBT.BossThreeInform)\n    \n    aura_env.SortDungeonData()\nend\n\n\naura_env.ExecuteCustomerSettings = function()\n    -- Plaguefall\n    if aura_env.config.O.PF.Slimes == true then\n        aura_env.SetDungeonValues(2289, 3, 81.50, true) -- with slimes\n    end\n    -- Halls of Atonement\n    local hoAPercent = HoANumOfLoyalStoneborn[aura_env.config.O.HoA.Stoneborn] -- Loyal Stoneborn\n    aura_env.SetDungeonValues(2287, 2, hoAPercent, true)\n    \n    --Sanguine Depths\n    aura_env.SetDungeonValues(2284, 2, 68.96, true)\n    if aura_env.config.O.SD.DifficultPack == false then\n        aura_env.SetDungeonValues(2284, 2, 74.73, true) -- without difficult pack\n    end\n    \n    if aura_env.config.O.SD.Bats > 0 then -- Ravenous Dreadbat\n        local sDPercent = aura_env.GetDungeonPercent(2284, 2) - (1.10 * aura_env.config.O.SD.Bats)\n        aura_env.SetDungeonValues(2284, 2, sDPercent, true)\n    end\nend\n\n\naura_env.SortDungeonData = function()\n    table.sort(DUNGEONS[DUNGEONID], function (left, right)\n            return left[2] < right[2]\n    end)\nend\n\n\naura_env.Initiate = function()\n    local currendDungeonId = ({GetInstanceInfo()})[8]\n    currendDungeonId = aura_env.ChangeDungeonIdForTazaveshGambit(currendDungeonId)\n    if currendDungeonId == DUNGEONID then return end\n    \n    DUNGEONS = DUNGEONDEFAULT\n    DUNGEONID = currendDungeonId\n    SECTION = 1    \n    aura_env.AdvancedOptions()\n    aura_env.SortDungeonData()\nend\n\n\naura_env.InformGroup = function(percentage)\n    local channel = CHANNELCONVERTER[aura_env.config.Msg.MsgChannel]\n    local percentageStr = string.format(\"%.2f %%\", percentage)\n    if percentageStr == \"0.00%\" then return end\n    SendChatMessage(\"[WA RM+]: We still need \" .. percentageStr, channel)\nend\n\n\naura_env.UpdateRemainingPercentage = function()\n    if DUNGEONDEFAULT[({GetInstanceInfo()})[8]] == nil then return end\n    aura_env.Initiate()\n    if not aura_env.config.AO.IsAdvancedOptionSelected then\n        aura_env.ExecuteCustomerSettings()\n    end\n    local currendPercentage = aura_env.GetCurrendPercentage()\n    if DUNGEONS[DUNGEONID] == nil or DUNGEONS[DUNGEONID][SECTION] == nil then return end\n    \n    while DUNGEONS[DUNGEONID][SECTION][2] <= 0 do\n        SECTION = SECTION + 1\n    end\n    local dungeonData = DUNGEONS[DUNGEONID][SECTION]\n    local bossEntcounter = dungeonData[1]\n    local neededPercent = dungeonData[2]\n    local shouldInfom = dungeonData[3]\n    local haveInformed = dungeonData[4]\n    local isBossKilled = ({C_Scenario.GetCriteriaInfo(bossEntcounter)})[3]\n    local remainingPercent = neededPercent - currendPercentage\n    local displayPercent = string.format(\"%.2f %%\", remainingPercent)\n    \n    if displayPercent == \"0.00%\" then\n        displayPercent = \"Done\"\n    end\n    \n    if remainingPercent > 0 and isBossKilled then\n        if (shouldInfom and not haveInformed) and aura_env.config.Msg.InformGroup then\n            aura_env.InformGroup(remainingPercent)\n            DUNGEONS[DUNGEONID][SECTION][4] = true\n        end\n        aura_env.DisplayText = \"|cFFFF0000\"..displayPercent..\"|r\"\n    elseif remainingPercent > 0 and not isBossKilled then\n        aura_env.DisplayText = displayPercent\n    elseif remainingPercent <= 0 and not isBossKilled then\n        aura_env.DisplayText = \"|cFF00FF00Done|r\"     \n    elseif remainingPercent <= 0 and isBossKilled then\n        SECTION = SECTION + 1\n        aura_env.DisplayText = \"|cFF00FF00Done!|r\"\n        aura_env.UpdateRemainingPercentage()\n    end\nend\n\n\naura_env.GetCurrendPercentage = function()\n    local steps = ({C_Scenario.GetStepInfo()})[3]\n    local total, _, _, current = select(5, C_Scenario.GetCriteriaInfo(steps))\n    if current then\n        current = tonumber(string.sub(current, 1, string.len(current) - 1)) or 0\n        local currentPercent = (current / total) * 100 \n        return currentPercent or 0\n    end\n    \n    return 0\nend",
