						["names"] = {
						},
						["custom"] = "function(states, event, arg1, arg2, arg3)\n    if event == \"OPTIONS\" then\n        states[\"\"] = {\n            text = \"\",\n            icon = 1323037,\n            progressType = \"static\",\n            changed = true,\n            show = true\n        }\n        return true\n    end\n    if event == \"HYLB_TOPRIGHT\" and arg1 and arg2 then\n        states[\"\"] = {\n            text = arg2,\n            icon = arg1,\n            progressType = \"static\",\n            changed = true,\n            show = true\n        }\n        aura_env.handle()\n        return true\n    elseif event == \"HYLB_RESET\" and arg1 then\n        aura_env.handle(true)\n        if states[\"\"] then\n            states[\"\"].show = false\n            states[\"\"].changed = true\n        end\n        return true\n    elseif (event == \"HYLB_TOPLEFT\" or event == \"HYLB_BOTTOMLEFT\" or event == \"HYLB_BOTTOMRIGHT\") and arg3 then\n        aura_env.region[\"button\"..arg3]:Hide()\n    end        \nend",
